interface User {
  id: number;
  name: string;
  email: string;
  role: "admin" | "editor" | "viewer";
  createdAt: string;
}

function formatUserBadge(user: User): string {
  const roleEmoji = { admin: "🔑", editor: "✏️", viewer: "👁️" };
  return `${roleEmoji[user.role]} ${user.name} <${user.email}>`;
}

const users: User[] = [
  { id: 1, name: "Alice Chen",  email: "alice@co.com",  role: "admin",  createdAt: "2022-01-15" },
  { id: 2, name: "Bob Taylor",  email: "bob@co.com",   role: "editor", createdAt: "2022-06-20" },
  { id: 3, name: "Carol Davis", email: "carol@co.com", role: "viewer", createdAt: "2023-02-10" },
];

for (const user of users) {
  console.log(formatUserBadge(user));
}

interface Product {
  id: number;
  name: string;
  price: number;
  description?: string;    // optional — may be undefined
  discount?: number;       // optional — may be undefined
  tags?: string[];         // optional — may be undefined
}

function formatProduct(p: Product): string {
  const finalPrice = p.discount
    ? p.price * (1 - p.discount)
    : p.price;

  const desc = p.description ?? "No description available";
  const tagStr = p.tags?.join(", ") ?? "none";

  return `${p.name}: $${finalPrice.toFixed(2)} | ${desc} | Tags: ${tagStr}`;
}

const products: Product[] = [
  { id: 1, name: "TypeScript Course", price: 49, description: "Master TS in 30 days", discount: 0.2, tags: ["programming", "web"] },
  { id: 2, name: "React Bootcamp",    price: 79 },
  { id: 3, name: "Node.js Basics",    price: 29, description: "Backend fundamentals" },
];

for (const p of products) {
  console.log(formatProduct(p));
}

interface OrderRecord {
  readonly id: string;
  readonly createdAt: string;
  readonly customerId: number;
  product: string;         // mutable — can be updated
  status: "pending" | "shipped" | "delivered" | "cancelled";
  amount: number;
}

function shipOrder(order: OrderRecord): OrderRecord {
  // order.id = "new-id";  // ← TypeScript error: Cannot assign to 'id' (readonly)
  return { ...order, status: "shipped" };
}

const order: OrderRecord = {
  id: "ORD-2024-001",
  createdAt: "2024-01-15",
  customerId: 42,
  product: "TypeScript Pro Plan",
  status: "pending",
  amount: 299,
};

const shipped = shipOrder(order);
console.log(`Order ${shipped.id}: ${shipped.status}`);
console.log(`Customer: ${shipped.customerId}`);
console.log(`Amount: $${shipped.amount}`);

interface ContentBase {
  id: number;
  authorId: number;
  authorName: string;
  createdAt: string;
  updatedAt: string;
}

interface BlogPost extends ContentBase {
  title: string;
  slug: string;
  body: string;
  tags: string[];
  published: boolean;
}

interface Comment extends ContentBase {
  postId: number;
  body: string;
  likes: number;
}

function summarise(content: ContentBase): string {
  return `[${content.id}] by ${content.authorName} on ${content.createdAt}`;
}

const post: BlogPost = {
  id: 1, authorId: 10, authorName: "Alice",
  createdAt: "2024-01-10", updatedAt: "2024-01-11",
  title: "TypeScript for Real Projects",
  slug: "ts-real-projects", body: "...",
  tags: ["typescript", "programming"], published: true,
};

const comment: Comment = {
  id: 99, authorId: 20, authorName: "Bob",
  createdAt: "2024-01-12", updatedAt: "2024-01-12",
  postId: 1, body: "Great article!", likes: 14,
};

console.log(summarise(post));
console.log(summarise(comment));
console.log(`Post tags: ${post.tags.join(", ")}`);
console.log(`Comment likes: ${comment.likes}`);
